'use server'

import { erpFetch } from '@/lib/erp-api'
import { revalidatePath } from 'next/cache'

/**
 * Phase 3 of the multi-dim attribute scoping feature.
 *
 * Operator review wizard for the auto-suggested scopes generated by
 * scanning observed product usage on the backend.
 *
 *   GET /api/inventory/product-attributes/scope-suggestions/?value_ids=…
 *   → list of suggestion dicts (see scope_suggester.py docstring)
 *
 *   POST /api/inventory/product-attributes/<id>/apply-scope/
 *   body: { add_categories: [...], add_countries: [...], add_brands: [...] }
 *   → diff dict describing what was added
 */

type ScopeRef = { id: number; name: string }

/**
 * Phase 6: AI-enriched scope suggestion. Present only when the org has
 * opted into AI ranking and the deterministic suggestion was within the
 * top-N enriched batch. The wizard tolerates missing ai_review by
 * falling back to deterministic-only display.
 */
export type AIScopeReview = {
    verdict: 'accept' | 'partial' | 'reject' | 'error'
    /** 0..1 — the LLM's independent confidence in the suggestion. */
    confidence: number
    /** One short sentence explaining the verdict, shown inline in the wizard. */
    rationale: string
    /** Per-axis agreement. False on an axis means the LLM thinks the
     *  deterministic suggestion is wrong on THAT axis only. */
    axes: { categories: boolean; countries: boolean; brands: boolean }
    /** True when this review came from the cache rather than a fresh call. */
    cached?: boolean
    /** True when the AI was skipped because the daily token cap was hit. */
    capped?: boolean
}

export type ScopeSuggestion = {
    value_id: number
    value_name: string
    group_id: number
    group_name: string
    product_count: number
    /** First 8 products using this value, ordered by name. The wizard
     *  shows these in an expandable details element so the operator
     *  can verify which products they're scoping before clicking Accept. */
    products_sample: { id: number; name: string }[]
    /** True when product_count > products_sample.length — UI shows
     *  "+N more" rather than implying the sample is exhaustive. */
    products_sample_truncated: boolean
    current_scope: { categories: ScopeRef[]; countries: ScopeRef[]; brands: ScopeRef[] }
    suggested_scope: { categories: ScopeRef[]; countries: ScopeRef[]; brands: ScopeRef[] }
    confidence: { categories: number; countries: number; brands: number }
    /** Phase 6: AI ranker output, optional. */
    ai_review?: AIScopeReview
}

export async function listScopeSuggestions(
    valueIds?: number[],
    opts?: { ai?: boolean; aiTopN?: number },
): Promise<ScopeSuggestion[]> {
    const params = new URLSearchParams()
    if (valueIds && valueIds.length) params.set('value_ids', valueIds.join(','))
    if (opts?.ai) params.set('ai', '1')
    if (opts?.aiTopN) params.set('ai_top_n', String(opts.aiTopN))
    const qs = params.toString() ? `?${params.toString()}` : ''
    try {
        const r = await erpFetch(`inventory/product-attributes/scope-suggestions/${qs}`)
        return Array.isArray(r) ? r : []
    } catch (e) {
        console.warn('[scope-suggestions] list failed', e)
        return []
    }
}

/**
 * Phase 6: per-org config for the AI scope ranker. The shape mirrors
 * the backend response — `has_provider` is a UI hint so the settings
 * card knows when to show "configure provider first" instead of just
 * a disabled toggle.
 */
export type AIScopeConfig = {
    enabled: boolean
    min_ai_confidence: number
    daily_token_cap: number
    tokens_used_today: number
    tokens_reset_at: string | null
    provider_id: number | null
    has_provider: boolean
    available_providers: {
        id: number
        name: string
        provider_type: string
        model_name: string
        is_default: boolean
    }[]
}

export async function getAIScopeConfig(): Promise<AIScopeConfig | null> {
    try {
        return await erpFetch('inventory/product-attributes/ai-scope-config/') as AIScopeConfig
    } catch (e) {
        console.warn('[ai-scope-config] get failed', e)
        return null
    }
}

export async function updateAIScopeConfig(
    patch: Partial<Pick<AIScopeConfig, 'enabled' | 'min_ai_confidence' | 'daily_token_cap' | 'provider_id'>>,
): Promise<{ success: boolean; config?: AIScopeConfig; message?: string }> {
    try {
        const r = await erpFetch('inventory/product-attributes/ai-scope-config/', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(patch),
        })
        return { success: true, config: r as AIScopeConfig }
    } catch (e: any) {
        return { success: false, message: e?.message || 'Update failed' }
    }
}

/**
 * Phase 5: preview the impact of a scope edit BEFORE applying it.
 *
 * Returns counts + a sample of products that would lose access to this
 * value if the proposed add/remove sets were applied. The wizard shows
 * this in a confirmation dialog when products_that_would_lose_access > 0.
 */
export type ScopeImpact = {
    products_currently_using_value: number
    products_that_would_lose_access: number
    losers_sample: { id: number; name: string }[]
}

export async function previewScopeImpact(
    valueId: number,
    delta: {
        add_categories?: number[]; remove_categories?: number[]
        add_countries?:  number[]; remove_countries?:  number[]
        add_brands?:     number[]; remove_brands?:     number[]
    },
): Promise<ScopeImpact | null> {
    try {
        const r = await erpFetch(`inventory/product-attributes/${valueId}/scope-impact/`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(delta),
        })
        return r as ScopeImpact
    } catch (e) {
        console.warn('[scope-impact] preview failed', e)
        return null
    }
}

export async function applyScopeSuggestion(
    valueId: number,
    add: { categories?: number[]; countries?: number[]; brands?: number[] },
): Promise<{ success: boolean; diff?: any; message?: string }> {
    try {
        const r = await erpFetch(`inventory/product-attributes/${valueId}/apply-scope/`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                add_categories: add.categories || [],
                add_countries:  add.countries  || [],
                add_brands:     add.brands     || [],
            }),
        })
        revalidatePath('/inventory/attributes')
        return { success: true, diff: r }
    } catch (e: any) {
        return { success: false, message: e?.message || 'Apply failed' }
    }
}
